// Берём ответ Polza/OpenAI-compatible если есть, иначе fallback
const chatId = $("Normalize Input").item.json.chat_id;
let text = "";
try {
  const j = $json;
  // OpenAI-compatible shape
  const c1 = j && j.choices && j.choices[0] && j.choices[0].message && j.choices[0].message.content;
  if (typeof c1 === 'string' && c1.trim()) text = c1.trim();
  // Legacy Ollama shape (на случай если кто-то вернёт старый формат)
  if (!text) {
    const c2 = j && j.message && j.message.content;
    if (typeof c2 === 'string' && c2.trim()) text = c2.trim();
  }
} catch (e) {}
if (!text) {
  text = 'Бот получил сообщение, но AI-модуль временно не подключен.';
}
return [{ json: { chat_id: chatId, text } }];

// CONTEXT: дата + объекты + окно занятости + DETERMINISTIC AVAILABILITY с расширенным парсером
const today = new Date();
const isoDate = today.toISOString().slice(0,10);
const currentYear = Number(isoDate.slice(0,4));


// Load gap windows
let gapWindows = [];
try { gapWindows = $('Load Gap Windows').all().map(i => i.json).filter(Boolean); } catch(e) {}

let apts = [];
try { apts = $('Load Apartments').all().map(i => i.json).filter(Boolean); } catch (e) { apts = []; }
let books = [];
try { books = $('Load Bookings Window').all().map(i => i.json).filter(Boolean); } catch (e) { books = []; }
const aptName = {};
for (const a of apts) { if (a && a.id) aptName[String(a.id)] = a.name; }
function isoOnly(v) {
  if (!v) return '';
  const s = String(v);
  return s.length >= 10 ? s.slice(0,10) : s;
}

// ---- date parsing helpers ----
const MONTHS = {
  'январ':1,'феврал':2,'март':3,'апрел':4,'мая':5,'май':5,'мае':5,
  'июн':6,'июл':7,'август':8,'авгус':8,'сентябр':9,'октябр':10,'ноябр':11,'декабр':12
};
function pad2(n){ n=String(n); return n.length<2?'0'+n:n; }
function ymd(y,m,dd){ return String(y)+'-'+pad2(m)+'-'+pad2(dd); }
function chooseYear(monthNum){
  const todayMonth = today.getUTCMonth()+1;
  if (monthNum >= todayMonth) return currentYear;
  return currentYear + 1;
}
function findMonth(text){
  const t = (text || '').toLowerCase();
  let bestKey = null, bestPos = -1;
  for (const k of Object.keys(MONTHS)) {
    const p = t.indexOf(k);
    if (p !== -1 && (bestPos === -1 || p < bestPos)) { bestKey = k; bestPos = p; }
  }
  return bestKey ? MONTHS[bestKey] : null;
}
// Strip markdown/asterisks etc to simplify regex
function normText(s){
  return (s||'').replace(/[*_`]+/g,' ').replace(/[ \t]+/g,' ').toLowerCase();
}
// Parse single date string like:
//   "12 июля 2026" / "12 июля" / "12.07.2026" / "12.07" / "12/07/2026"
function parseSingleDate(s){
  if (!s) return null;
  const t = s.trim().toLowerCase();
  let m = t.match(/(\d{1,2})[.\/](\d{1,2})(?:[.\/](\d{2,4}))?/);
  if (m){
    const d=+m[1], mo=+m[2];
    let y = m[3] ? (+m[3] < 100 ? 2000 + +m[3] : +m[3]) : chooseYear(mo);
    return ymd(y, mo, d);
  }
  m = t.match(/(\d{1,2})\s*([а-яё]+)(?:\s+(\d{4}))?/);
  if (m){
    const d=+m[1], mn=findMonth(m[2]);
    if (mn){
      const y = m[3] ? +m[3] : chooseYear(mn);
      return ymd(y, mn, d);
    }
  }
  return null;
}
// Main parser, supports multiple structured forms.
function parseDateRange(rawText){
  if (!rawText) return null;
  const raw = String(rawText);
  const t = normText(raw);

  // 0) "Заезд: ... / Выезд: ..." (structured) — checkin / checkout / from / to / arrival / departure
  const reCheckin  = /(?:заезд|заселени[ея]|приезд|c\s*даты|c|with|from|arrival)\s*[:\-—]?\s*([0-9]{1,2}[.\/][0-9]{1,2}(?:[.\/][0-9]{2,4})?|[0-9]{1,2}\s+[а-яё]+(?:\s+\d{4})?)/i;
  const reCheckout = /(?:выезд|выселени[ея]|отъезд|до\s*даты|до|until|to|departure|checkout)\s*[:\-—]?\s*([0-9]{1,2}[.\/][0-9]{1,2}(?:[.\/][0-9]{2,4})?|[0-9]{1,2}\s+[а-яё]+(?:\s+\d{4})?)/i;
  const mIn  = t.match(reCheckin);
  const mOut = t.match(reCheckout);
  if (mIn && mOut) {
    const a = parseSingleDate(mIn[1]);
    const b = parseSingleDate(mOut[1]);
    if (a && b) return { start: a, end: b };
  }

  // 1) "DD.MM[.YYYY] - DD.MM[.YYYY]"  /  "с DD.MM по DD.MM"
  let m = t.match(/(\d{1,2})[.\/](\d{1,2})(?:[.\/](\d{2,4}))?\s*[-–—по]+\s*(\d{1,2})[.\/](\d{1,2})(?:[.\/](\d{2,4}))?/);
  if (m){
    const d1=+m[1], mo1=+m[2], y1=m[3]?(+m[3]<100?2000+ +m[3]:+m[3]):chooseYear(mo1);
    const d2=+m[4], mo2=+m[5], y2=m[6]?(+m[6]<100?2000+ +m[6]:+m[6]):chooseYear(mo2);
    return { start: ymd(y1,mo1,d1), end: ymd(y2,mo2,d2) };
  }

  // 2) "с D MONTH (YYYY) по D MONTH (YYYY)"
  m = t.match(/с\s+(\d{1,2})\s+([а-яё]+)(?:\s+(\d{4}))?\s+по\s+(\d{1,2})\s+([а-яё]+)(?:\s+(\d{4}))?/);
  if (m){
    const d1=+m[1], d2=+m[4];
    const mn1=findMonth(m[2]), mn2=findMonth(m[5]);
    if (mn1 && mn2){
      const y1 = m[3]?+m[3]:chooseYear(mn1);
      const y2 = m[6]?+m[6]:((mn2 < mn1) ? y1+1 : y1);
      return { start: ymd(y1,mn1,d1), end: ymd(y2,mn2,d2) };
    }
  }

  // 3) "D MONTH — D MONTH (YYYY)"  /  "D MONTH - D MONTH (YYYY)"
  m = t.match(/(\d{1,2})\s+([а-яё]+)\s*[-–—]\s*(\d{1,2})\s+([а-яё]+)(?:\s+(\d{4}))?/);
  if (m){
    const d1=+m[1], d2=+m[3];
    const mn1=findMonth(m[2]), mn2=findMonth(m[4]);
    if (mn1 && mn2){
      const y1 = m[5]?+m[5]:chooseYear(mn1);
      const y2 = (mn2 < mn1) ? y1+1 : y1;
      return { start: ymd(y1,mn1,d1), end: ymd(y2,mn2,d2) };
    }
  }

  // 4) "(с)? D по D MONTH (YYYY)?" — same month
  m = t.match(/(?:с\s+)?(\d{1,2})\s*[-–—по]+\s*(\d{1,2})\s+([а-яё]+)(?:\s+(\d{4}))?/);
  if (m){
    const d1=+m[1], d2=+m[2];
    const mn=findMonth(m[3]);
    if (mn){
      const y = m[4]?+m[4]:chooseYear(mn);
      return { start: ymd(y,mn,d1), end: ymd(y,mn,d2) };
    }
  }

  // 5) Today/tomorrow shortcuts
  if (/завтра/.test(t)) {
    const tm  = new Date(today.getTime() + 86400000);
    const tm2 = new Date(today.getTime() + 2*86400000);
    return { start: ymd(tm.getUTCFullYear(),tm.getUTCMonth()+1,tm.getUTCDate()),
             end:   ymd(tm2.getUTCFullYear(),tm2.getUTCMonth()+1,tm2.getUTCDate()) };
  }
  if (/сегодня/.test(t)) {
    const tm2 = new Date(today.getTime()+86400000);
    return { start: isoDate, end: ymd(tm2.getUTCFullYear(),tm2.getUTCMonth()+1,tm2.getUTCDate()) };
  }
  return null;
}

function overlap(aStart, aEnd, bStart, bEnd){
  return aStart < bEnd && bStart < aEnd;
}

const norm = $('Normalize Input').item.json;
const inputText = norm.input_text || '';
const range = parseDateRange(inputText);

let lines = [];
lines.push('СЕГОДНЯ: ' + isoDate);

if (apts.length > 0) {
  lines.push('ОБЪЕКТЫ ДОМА (источник: PostgreSQL apartments, актуально):');
  for (const a of apts) {
    const desc = (a.description && String(a.description).trim()) ? ' ' + String(a.description).trim() : '';
    lines.push('- ' + a.name + ': до ' + a.max_guests + ' гостей, ' + a.rooms + ' комн., базовая цена ' + a.base_price + ' ₽.' + desc);
  }
} else {
  lines.push('ОБЪЕКТЫ ДОМА: справочник apartments сейчас недоступен.');
}

lines.push('');
lines.push('ЗАНЯТОСТЬ (источник: PostgreSQL bookings, окно 90 дней от сегодня):');
if (books.length > 0) {
  for (const b of books) {
    const aptId = String(b.apartment_id);
    const label = aptName[aptId] || ('apt ' + aptId);
    const ci = isoOnly(b.checkin_at);
    const co = isoOnly(b.checkout_at);
    const src = b.source ? ', source ' + b.source : '';
    lines.push('- ' + label + ': ' + ci + ' → ' + co + ' (' + b.status + ')' + src);
  }
} else {
  lines.push('Текущих броней в окне 90 дней в БД нет.');
}

let datesParsed = false;
lines.push('');
if (range) {
  datesParsed = true;
  lines.push('ЗАПРОШЕННЫЙ ПЕРИОД:');
  lines.push(range.start + ' → ' + range.end);
  lines.push('');
  lines.push('РАСЧЁТ ДОСТУПНОСТИ ПО БД (выполнен системой, не пересчитывать):');
  const freeOnes = [];
  for (const a of apts) {
    const aptId = String(a.id);
    const conflicts = books.filter(b => String(b.apartment_id) === aptId
      && overlap(range.start, range.end, isoOnly(b.checkin_at), isoOnly(b.checkout_at)));
    if (conflicts.length === 0) {
      lines.push('- ' + a.name + ': СВОБОДЕН ПО ДАННЫМ БД, финальное подтверждение за владельцем.');
      freeOnes.push(a.name);
    } else {
      const pieces = conflicts.map(b => isoOnly(b.checkin_at)+' → '+isoOnly(b.checkout_at)).join('; ');
      lines.push('- ' + a.name + ': ЗАНЯТ. Пересечения: ' + pieces + '.');
    }
  }
  lines.push('');
  lines.push('СВОБОДНЫЕ ПО ДАННЫМ БД:');
  lines.push(freeOnes.length ? freeOnes.join(', ') : 'нет');
} else {
  lines.push('РАСЧЁТ ДОСТУПНОСТИ ПО БД: даты не распознаны системой.');
  lines.push('Действие: задать пользователю один уточняющий вопрос — попросить дату заезда, дату выезда и количество гостей. Не объявлять никакие номера свободными.');
}

lines.push('');
lines.push('ВАЖНО:');
lines.push('Расчёт доступности уже выполнен системой выше. Не пересчитывай даты самостоятельно.');
lines.push(datesParsed
  ? 'Используй только блок РАСЧЁТ ДОСТУПНОСТИ ПО БД. Если в нём номер помечен ЗАНЯТ — НЕЛЬЗЯ называть его свободным. Если "СВОБОДНЫЕ ПО ДАННЫМ БД: нет" — на запрошенный период свободных номеров нет, предложи посмотреть другие даты по ссылке Homereserve.'
  : 'Поскольку даты не распознаны, тебе ЗАПРЕЩЕНО объявлять любые номера свободными или занятыми. Единственный допустимый ответ — уточняющий вопрос: попроси дату заезда, дату выезда и количество гостей.');


// GAP WINDOWS block
lines.push('');
lines.push('МАЛЕНЬКИЕ ОКНА / GAP WINDOWS (1-3 ночи между бронями):');
if (gapWindows.length === 0) {
  lines.push('Маленьких окон в ближайшие 90 дней не найдено.');
} else {
  for (const g of gapWindows) {
    const loss = g.estimated_loss ? ` (~${Number(g.estimated_loss).toLocaleString('ru')} ₽ потери)` : '';
    lines.push(`- Номер ${g.apartment_id} (${g.apartment_name}): ${g.gap_start} — ${g.gap_end} (${g.nights} н.)${loss}`);
    lines.push(`  Рекомендация: ${g.recommendation}`);
  }
}

lines.push('');
lines.push('ССЫЛКА ДЛЯ ПРОСМОТРА И БРОНИРОВАНИЯ:');
lines.push('https://homereserve.ru/m66FXMW0XO/list-preview');

const context_text = lines.join('\n');
return [{ json: { context_text, input_text: norm.input_text, chat_id: norm.chat_id, is_voice: !!norm.is_voice, dates_parsed: datesParsed } }];
